select
id, ticket_main_text_id, order_id, status, is_deleted, create_user, update_user, create_time, update_time
from ticket_main_text_order

    1 = 1 and is_deleted = 0

        and id = #{id}


        and ticket_main_text_id = #{ticketMainTextId}


        and order_id = #{orderId}


        and status = #{status}


        and is_deleted = #{isDeleted}


        and create_user = #{createUser}


        and update_user = #{updateUser}


        and create_time = #{createTime}


        and update_time = #{updateTime}

